  1	import React, { useMemo } from 'react';
  2	import {
  3	  ChartsProvider,
  4	  generateChartsTheme,
  5	  getTheme,
  6	  PersesChartsTheme,
  7	  typography,
  8	} from '@perses-dev/components';
  9	import { ThemeProvider } from '@mui/material';
 10	import {
 11	  DataQueriesProvider,
 12	  dynamicImportPluginLoader,
 13	  PluginModuleResource,
 14	  PluginRegistry,
 15	  TimeRangeProvider,
 16	  useDataQueries,
 17	} from '@perses-dev/plugin-system';
 18	import {
 19	  DatasourceResource,
 20	  Definition,
 21	  DurationString,
 22	  GlobalDatasourceResource,
 23	  TimeRangeValue,
 24	  UnknownSpec,
 25	} from '@perses-dev/core';
 26	import panelsResource from '@perses-dev/panels-plugin/plugin.json';
 27	import tempoResource from '@perses-dev/tempo-plugin/plugin.json';
 28	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
 29	import { DatasourceApi, DatasourceStoreProvider, VariableProvider } from '@perses-dev/dashboards';
 30	import { ChartThemeColor, getThemeColors } from '@patternfly/react-charts/victory';
 31	import { TempoInstance } from '../hooks/useTempoInstance';
 32	import { getProxyURLFor } from '../hooks/api';
 33	import { ErrorBoundary } from 'react-error-boundary';
 34	import { ErrorAlert } from './ErrorAlert';
 35	import { NoTempoInstanceSelectedState } from './NoTempoInstanceSelectedState';
 36	import { LoadingState } from './LoadingState';
 37	import { usePatternFlyTheme } from './console/utils/usePatternFlyTheme';
 38	
 39	class DatasourceApiImpl implements DatasourceApi {
 40	  constructor(public proxyDatasource: GlobalDatasourceResource) {}
 41	
 42	  getDatasource(): Promise<DatasourceResource | undefined> {
 43	    return Promise.resolve(undefined);
 44	  }
 45	  getGlobalDatasource(): Promise<GlobalDatasourceResource | undefined> {
 46	    return Promise.resolve(this.proxyDatasource);
 47	  }
 48	  listDatasources(): Promise<DatasourceResource[]> {
 49	    return Promise.resolve([]);
 50	  }
 51	  listGlobalDatasources(): Promise<GlobalDatasourceResource[]> {
 52	    return Promise.resolve([this.proxyDatasource]);
 53	  }
 54	  buildProxyUrl(): string {
 55	    return '/';
 56	  }
 57	}
 58	
 59	// Override eChart defaults with PatternFly colors.
 60	const patternflyBlue300 = '#2b9af3';
 61	const patternflyBlue400 = '#0066cc';
 62	const patternflyBlue500 = '#004080';
 63	const patternflyBlue600 = '#002952';
 64	const defaultPaletteColors = [patternflyBlue400, patternflyBlue500, patternflyBlue600];
 65	
 66	const patternflyChartsMultiUnorderedPalette = getThemeColors(
 67	  ChartThemeColor.multiUnordered,
 68	).chart.colorScale.flatMap((cssColor) => {
 69	  // colors are stored as 'var(--pf-chart-theme--multi-color-unordered--ColorScale--3400, #73c5c5)'
 70	  // need to extract the hex value, because fillStyle() of <canvas> does not support CSS vars
 71	  const match = cssColor.match(/#[a-fA-F0-9]+/);
 72	  return match ? [match[0]] : [];
 73	});
 74	
 75	// PluginRegistry configuration to allow access to
 76	// visualization panels/charts (@perses-dev/panels-plugin)
 77	// and data handlers for tempo (@perses-dev/tempo-plugin).
 78	const pluginLoader = dynamicImportPluginLoader([
 79	  {
 80	    resource: panelsResource as PluginModuleResource,
 81	    importPlugin: () => import('@perses-dev/panels-plugin'),
 82	  },
 83	  {
 84	    resource: tempoResource as PluginModuleResource,
 85	    importPlugin: () => import('@perses-dev/tempo-plugin'),
 86	  },
 87	]);
 88	
 89	const queryClient = new QueryClient({
 90	  defaultOptions: {
 91	    queries: {
 92	      refetchOnWindowFocus: false,
 93	      retry: 0,
 94	    },
 95	  },
 96	});
 97	
 98	interface PersesWrapperProps {
 99	  children?: React.ReactNode;
100	}
101	
102	export function PersesWrapper({ children }: PersesWrapperProps) {
103	  const { theme } = usePatternFlyTheme();
104	
105	  const muiTheme = getTheme(theme, {
106	    typography: {
107	      ...typography,
108	      fontFamily: 'var(--pf-t--global--font--family--body)',
109	    },
110	    shape: {
111	      borderRadius: 0,
112	    },
113	  });
114	
115	  const chartsTheme: PersesChartsTheme = generateChartsTheme(muiTheme, {
116	    echartsTheme: {
117	      color: patternflyChartsMultiUnorderedPalette,
118	    },
119	    thresholds: {
120	      defaultColor: patternflyBlue300,
121	      palette: defaultPaletteColors,
122	    },
123	  });
124	
125	  return (
126	    <ThemeProvider theme={muiTheme}>
127	      <ChartsProvider chartsTheme={chartsTheme}>
128	        <PluginRegistry pluginLoader={pluginLoader}>
129	          <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
130	        </PluginRegistry>
131	      </ChartsProvider>
132	    </ThemeProvider>
133	  );
134	}
135	
136	interface PersesDashboardWrapperProps {
137	  timeRange?: TimeRangeValue;
138	  setTimeRange?: (value: TimeRangeValue) => void;
139	  children?: React.ReactNode;
140	}
141	
142	export function PersesDashboardWrapper({
143	  timeRange = { pastDuration: '0s' },
144	  setTimeRange,
145	  children,
146	}: PersesDashboardWrapperProps) {
147	  return (
148	    <TimeRangeProvider timeRange={timeRange} setTimeRange={setTimeRange}>
149	      <VariableProvider>{children}</VariableProvider>
150	    </TimeRangeProvider>
151	  );
152	}
153	
154	interface PersesTempoDatasourceWrapperProps {
155	  tempo: TempoInstance | undefined;
156	  queries: Definition<UnknownSpec>[];
157	  duration?: DurationString;
158	  children?: React.ReactNode;
159	}
160	
161	export function PersesTempoDatasourceWrapper({
162	  tempo,
163	  queries,
164	  children,
165	}: PersesTempoDatasourceWrapperProps) {
166	  const datasourceApi = useMemo(() => {
167	    const proxyDatasource: GlobalDatasourceResource = {
168	      kind: 'GlobalDatasource',
169	      metadata: { name: 'TempoProxy' },
170	      spec: {
171	        default: true,
172	        plugin: {
173	          kind: 'TempoDatasource',
174	          spec: {
175	            directUrl: tempo ? getProxyURLFor(tempo) : '',
176	          },
177	        },
178	      },
179	    };
180	    return new DatasourceApiImpl(proxyDatasource);
181	  }, [tempo]);
182	
183	  if (!tempo) {
184	    return <NoTempoInstanceSelectedState />;
185	  }
186	
187	  return (
188	    <DatasourceStoreProvider datasourceApi={datasourceApi}>
189	      <DataQueriesProvider definitions={queries}>{children}</DataQueriesProvider>
190	    </DatasourceStoreProvider>
191	  );
192	}
193	
194	interface TracePanelWrapperProps {
195	  noResults?: React.ReactNode;
196	  children?: React.ReactNode;
197	}
198	
199	/**
200	 * TraceQueryPanelWrapper intercepts the trace query status and displays PatternFly native empty and loading states
201	 * instead of the Material UI empty and loading states used by Perses.
202	 */
203	export function TraceQueryPanelWrapper({ noResults, children }: TracePanelWrapperProps) {
204	  const { isFetching, isLoading, queryResults } = useDataQueries('TraceQuery');
205	
206	  if (isLoading || isFetching) {
207	    return <LoadingState />;
208	  }
209	
210	  const queryError = queryResults.find((d) => d.error);
211	  if (queryError) {
212	    return <ErrorAlert error={queryError.error as Error} />;
213	  }
214	
215	  const dataFound = queryResults.some(
216	    (traceData) => (traceData.data?.searchResult ?? []).length > 0 || traceData.data?.trace,
217	  );
218	  if (!dataFound && noResults) {
219	    return <>{noResults}</>;
220	  }
221	
222	  return (
223	    <ErrorBoundary FallbackComponent={ErrorAlert} resetKeys={[]}>
224	      {children}
225	    </ErrorBoundary>
226	  );
227	}

